    if (lid == 0) {
        partial_sums[get_group_id(0)] = buffer[0];
    }

    barrier(CLK_LOCAL_MEM_FENCE);
}

__kernel void kernel(__global double *arrayX,
                     __global double *arrayY,
                     __global double *CDF,
                     __global double *u,
                     __global double *xj,
                     __global double *yj,
                     int Nparticles) {
    int i = (int)get_global_id(0);

    if (i < Nparticles) {
        int index = -1;
        int x;

        for (x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) {
            index = Nparticles - 1;
        }

        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}
